{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Based on federal poverty guidelines (exact dollar amounts not specified in sources; vary by household size and must meet low-income thresholds). Income sources and other factors affect eligibility. Priority for elderly (60+), disabled, households with children under 6, and vulnerable populations.[1][2][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Household must qualify under Department of Energy guidelines including income, household size, energy use, and other factors.[1]", "Provide proof of monthly income for entire household.[2]", "Live in service area (e.g., specific counties like Alameda for some providers).[2]", "Own residence or have landlord approval for renters.[2]", "Home at least 5 years old in some related programs.[7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Installation of weatherization and energy efficiency measures (e.g., insulation, air sealing, heater/water heater repair or replacement, duct sealing). Average yearly savings over $400 per household. Services every 5 years. Makes homes warmer in winter, cooler in summer, reduces energy costs.[1][2]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Call local provider (e.g., CSET Weatherization Hotline: 1-844-224-1316).[5]", "Contact Spectrum Community Services for Alameda County.[2]", "Visit agency website or call for appointment (e.g., 211 LA for LA area).[3]", "Call state administrator via CSD for local providers.[1][6]"],
    "processing_time": "Not specified; emergency appointments for disconnect notices within 1-2 days in some areas.[3]",
    "waitlist": "Prioritization based on need, income, vulnerable populations; potential waitlists due to funding and demand.[1]",
    "forms": ["Complete Weatherization form with HEAP application if applicable; no specific form number listed.[3]"],
    "documents": ["Proof of all household income (e.g., last 4 weeks pay stubs, Social Security, bank statements).[2][5][9]", "Most recent electric, gas, or propane bill.[2][5]", "Social Security cards for household members.[3][5]", "Proof of residence (e.g., utility bill, rental receipt).[3]", "Landlord approval if renter.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through local community-based service providers; must contact local provider for service area (e.g., Alameda County via Spectrum).[1][2]",
    "regional_variations": "Different local providers by region (e.g., Spectrum in Alameda, CSET, 211 LA in Los Angeles area); services may vary slightly by provider and funding; priority and availability differ.[1][2][3][5]",
    "offices_or_providers": ["CSD local service providers statewide.[1]", "Spectrum Community Services (Alameda County).[2]", "CSET (call 1-844-224-1316).[5]", "211 LA providers.[3]"]
  },
  "official_source": "https://www.csd.ca.gov/Pages/Residential-Energy-Efficiency.aspx",
  "gotchas": ["Not all services guaranteed; partial list only.[2]", "Priorities for elderly (60+), disabled, young children—may affect wait times.[1][2][3]", "Separate from LIWP (multifamily/farmworker focus) and ESA (PG&E-specific).[1][4][7]", "Requires landlord permission for renters; homeowner or renter both eligible but site-specific.[1][2][8]", "Services once every 5 years, not annual.[2]", "Funding from DOE, state; availability depends on local provider capacity.[1][5]"],
  "data_shape_notes": "Administered statewide via local providers with regional variations in offices, wait times, and exact services; priority-based access for vulnerable households like elderly; income at poverty guidelines without published table; no fixed age requirement but elderly prioritized."
}

{
  "name": "State Supplementary Payment (SSP)",
  "eligibility": {
    "age": 65,
    "income_limits": "Income must be limited such that countable monthly income (after disregards like first $20 of any income, first $65 of earned income plus half the rest, SNAP, tax refunds, etc.) does not exceed the maximum SSI/SSP benefit: $1,206.94 for an individual ($967 federal + $239.94 SSP) or $2,057.83 for a couple ($1,450 federal + $607.83 SSP). Exact limits vary by living arrangement, other income, and SSA calculations; no fixed table by household size beyond individual/couple as SSP supplements SSI federally determined eligibility.[1][3][4][5][7]",
    "asset_limits": "Resources (assets) must be under $2,000 for an individual or $3,000 for an eligible couple. Countable assets include cash, bank accounts, stocks, etc.; exempt assets typically include one home, one vehicle, household goods, life insurance up to certain values, and burial funds.[1][2][3][6]",
    "other_requirements": [
      "Must qualify for federal SSI: disabled, blind, or age 65+; unable to work due to disability (if under 65); U.S. citizen or qualified non-citizen (e.g., permanent resident with 40 work quarters, refugee/asylee in first 5 years, veteran/spouse/child); live in U.S.; apply for other benefits.[1][2][3][4]",
      "SSP eligibility follows SSI automatically in California; no separate state test.[3][5][7]"
    ]
  },
  "benefits": {
    "type": "financial",
    "value": "Cash payment supplementing federal SSI: maximum $239.94/month for individual ($1,206.94 total SSI/SSP); $607.83/month for couple ($2,057.83 total). Reduced dollar-for-dollar by other countable income; varies by living arrangement.[1][3][5][7]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": [
      "Phone: Call Social Security Administration at 1-800-772-1213 (TTY 1-800-325-0778).[2]",
      "Online: Apply via SSA website at ssa.gov/ssi.",
      "In-person: Local SSA office (find via ssa.gov/locator)."
    ],
    "processing_time": "SSA determines; initial decision varies, with periodic re-verification. No specific timeline stated.[4]",
    "waitlist": null,
    "forms": ["SSI application (Form SSA-8000 or online equivalent)"],
    "documents": [
      "Proof of age (birth certificate, ID), income (pay stubs, benefits statements), resources (bank statements), medical records (if disability-based), immigration status (if non-citizen), living arrangement details.[1][2][4][6]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "California residents only; administered statewide by SSA.[2][3][5]",
    "regional_variations": null,
    "offices_or_providers": ["Social Security Administration offices statewide"]
  },
  "official_source": "https://www.cdss.ca.gov/inforesources/cdss-programs/ssi-ssp/ssi-ssp-eligibility-summary",
  "gotchas": [
    "SSP is automatic with SSI eligibility but reduced by other income; not a separate application.[3][5][7]",
    "No annual COLA for SSP since 2009/2011 cuts, so benefits lag inflation.[5][7]",
    "Must apply for all other benefits (e.g., SNAP); in-kind food/shelter can count as income.[2][4][6]",
    "Non-citizens need specific qualifications; disability must meet strict SSA definition (lasting 1+ year, prevents substantial work).[1][4]",
    "Living arrangements affect payment levels (e.g., shared housing reduces amount).[1][3]"
  ],
  "data_shape_notes": "SSP automatically supplements federal SSI with fixed state add-on amounts for individual/couple; eligibility tied to federal SSI income/resource tests with California-specific grant levels; no separate state income/asset limits or household size table beyond couple."
}

{
  "name": "Caregiver Resource Centers (CRC)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits specified; services are available to unpaid family caregivers of adults with chronic debilitating conditions including dementia, Alzheimer’s, stroke, Parkinson’s, Huntington’s, multiple sclerosis, traumatic brain injury, or other cognitive disorders[4][5][6].",
    "asset_limits": "No asset limits or exclusions mentioned; program focuses on need rather than financial means testing[4][5].",
    "other_requirements": ["Unpaid family caregivers serving individuals with specified chronic health conditions", "California resident with access to a local CRC (statewide coverage via 11 centers)", "No formal age requirement for care recipient, but targeted at adults with debilitating conditions[4][5][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Core services include: Specialized information and referral for caregiver stress, diagnoses, and resources; family consultation and care planning; respite care (financial assistance for in-home support, adult day care, short-term/weekend care, transportation); short-term counseling (individual, family, group); support groups (online/in-person); professional training workshops; legal/financial consultation (Powers of Attorney, Advance Directives, estate planning, conservatorships); education workshops on cognitive disorders, dementia, long-term care, stress management. Serves over 14,000 families annually; no specific dollar amounts or hours per week stated[4][5].",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local CRC by phone (e.g., Inland CRC: (909) 514-1404 or (800) 675-6694); visit caregivercalifornia.org for center locator and contacts; email specific centers (e.g., info@inlandcaregivers.org); in-person at 11 nonprofit centers covering all counties; CareNav™ online tool for customized resource matching[4][5][6][8]"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["No specific form names/numbers identified; intake process via phone/consultation with assigned CRC[2][5]"],
    "documents": ["No standard documents listed; may require verification of caregiver/resident status or care recipient condition during intake, but consent not typically required for most services[2][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Every county covered by one of 11 nonprofit centers; e.g., Inland CRC serves Inyo, Mono, Riverside, San Bernardino[4][6]",
    "regional_variations": "Services delivered via 11 regional nonprofit centers with local contacts, phone numbers, and websites; availability of specific services (e.g., respite funding levels) may vary by center and funding[4][5][6]",
    "offices_or_providers": ["11 nonprofit centers statewide; examples: Inland Caregiver Resource Center (www.inlandcaregivers.org), Los Angeles CRC (losangelescrc.usc.edu), full list at caregivercalifornia.org and dhcs.ca.gov[4][5][6][7]"]
  },
  "official_source": "https://www.dhcs.ca.gov/services/MH/Pages/AdultsCaregiverResourceCenters.aspx",
  "gotchas": ["Not a paid caregiver program—focuses on support services for unpaid family caregivers, not direct payment (compare to IHSS/Medicaid for compensation)[1][3][9]; no means-testing but targeted to specific conditions (not general elderly care); contact local CRC as services/providers differ regionally; not a Medicaid enrollment program but can refer to one[4][5][8][9]"],
  "data_shape_notes": "Statewide network of 11 regional nonprofit centers with no income/asset test; services customized by condition and local provider; differs from paid programs like IHSS by emphasizing counseling, respite, and planning over wages"
}
